+#[test]
+fn error_recovery() {
+    let test_name = "e2e_agent_loop_error_recovery";
+    let harness = TestHarness::new(test_name);
+
+    let outcome = run_scenario(
+        &harness,
+        Scenario::ErrorRecovery,
+        "Call an invalid tool and then recover.",
